import{_ as t,c as s,o as a,a1 as e}from"./chunks/framework.DILC4Csi.js";const k=JSON.parse('{"title":"クイックスタート：5分でopencode-notifyを始める | opencode-notifyチュートリアル","description":"opencode-notifyプラグインのインストール方法を学び、5分以内に設定を完了して最初のデスクトップ通知を体験しましょう。本チュートリアルでは、OCXパッケージマネージャーと手動インストールの2つの方法を解説し、macOS、Windows、Linuxに対応しています。AIタスク完了時に即座に通知を受け取れます。","frontmatter":{"title":"クイックスタート：5分でopencode-notifyを始める | opencode-notifyチュートリアル","sidebarTitle":"5分で通知を受け取る","subtitle":"クイックスタート：5分でopencode-notifyを始める","description":"opencode-notifyプラグインのインストール方法を学び、5分以内に設定を完了して最初のデスクトップ通知を体験しましょう。本チュートリアルでは、OCXパッケージマネージャーと手動インストールの2つの方法を解説し、macOS、Windows、Linuxに対応しています。AIタスク完了時に即座に通知を受け取れます。","tags":["入門","インストール","クイックスタート"],"prerequisite":[],"order":10},"headers":[],"relativePath":"ja/kdcokenny/opencode-notify/start/quick-start/index.md","filePath":"ja/kdcokenny/opencode-notify/start/quick-start/index.md"}'),n={name:"ja/kdcokenny/opencode-notify/start/quick-start/index.md"};function o(l,i,d,r,h,p){return a(),s("div",null,[...i[0]||(i[0]=[e(`<h1 id="クイックスタート-5分でopencode-notifyを始める" tabindex="-1">クイックスタート：5分でopencode-notifyを始める <a class="header-anchor" href="#クイックスタート-5分でopencode-notifyを始める" aria-label="Permalink to &quot;クイックスタート：5分でopencode-notifyを始める&quot;">​</a></h1><h2 id="このチュートリアルで学べること" tabindex="-1">このチュートリアルで学べること <a class="header-anchor" href="#このチュートリアルで学べること" aria-label="Permalink to &quot;このチュートリアルで学べること&quot;">​</a></h2><ul><li>3分以内にopencode-notifyプラグインをインストール</li><li>最初のデスクトップ通知をトリガーし、インストール成功を確認</li><li>各インストール方法の違いと適用シーンを理解</li></ul><h2 id="今あなたが抱えている課題" tabindex="-1">今あなたが抱えている課題 <a class="header-anchor" href="#今あなたが抱えている課題" aria-label="Permalink to &quot;今あなたが抱えている課題&quot;">​</a></h2><p>AIにタスクを依頼した後、別のウィンドウで作業を続けていませんか？30秒ごとに画面を切り替えて確認する日々——完了した？エラー？それとも権限待ち？opencode-notifyはまさにこの問題を解決するために生まれました。</p><p>この頻繁な切り替えは、集中力を途切れさせ、時間を無駄にします。</p><h2 id="こんな時に使おう" tabindex="-1">こんな時に使おう <a class="header-anchor" href="#こんな時に使おう" aria-label="Permalink to &quot;こんな時に使おう&quot;">​</a></h2><p><strong>以下のシーンでopencode-notifyを有効にしましょう</strong>：</p><ul><li>AIがタスクを実行中に、他のアプリに切り替えることが多い</li><li>AIがあなたを必要とした時、すぐに通知を受けたい</li><li>集中を維持しながら、重要なイベントを見逃したくない</li></ul><h2 id="基本コンセプト" tabindex="-1">基本コンセプト <a class="header-anchor" href="#基本コンセプト" aria-label="Permalink to &quot;基本コンセプト&quot;">​</a></h2><p>opencode-notifyの仕組みはシンプルです：OpenCodeのイベントを監視し、重要なタイミングでネイティブデスクトップ通知を送信します。</p><p><strong>通知されるイベント</strong>：</p><ul><li>✅ タスク完了（Session idle）</li><li>✅ 実行エラー（Session error）</li><li>✅ 権限が必要（Permission updated）</li></ul><p><strong>通知されないイベント</strong>：</p><ul><li>❌ 各サブタスクの完了（ノイズになるため）</li><li>❌ ターミナルがフォーカスされている時のすべてのイベント（画面を見ているので通知不要）</li></ul><h2 id="🎒-始める前の準備" tabindex="-1">🎒 始める前の準備 <a class="header-anchor" href="#🎒-始める前の準備" aria-label="Permalink to &quot;🎒 始める前の準備&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">前提条件</p><ul><li><a href="https://github.com/sst/opencode" target="_blank" rel="noreferrer">OpenCode</a>がインストール済み</li><li>利用可能なターミナル（macOS Terminal、iTerm2、Windows Terminalなど）</li><li>macOS/Windows/Linuxシステム（すべて対応）</li></ul></div><h2 id="手順" tabindex="-1">手順 <a class="header-anchor" href="#手順" aria-label="Permalink to &quot;手順&quot;">​</a></h2><h3 id="ステップ1-インストール方法を選択" tabindex="-1">ステップ1：インストール方法を選択 <a class="header-anchor" href="#ステップ1-インストール方法を選択" aria-label="Permalink to &quot;ステップ1：インストール方法を選択&quot;">​</a></h3><p>opencode-notifyには2つのインストール方法があります：</p><table tabindex="0"><thead><tr><th>方法</th><th>適用シーン</th><th>メリット</th><th>デメリット</th></tr></thead><tbody><tr><td><strong>OCXパッケージマネージャー</strong></td><td>ほとんどのユーザー</td><td>ワンクリックインストール、自動更新、依存関係の完全管理</td><td>OCXの事前インストールが必要</td></tr><tr><td><strong>手動インストール</strong></td><td>特殊な要件がある場合</td><td>完全な制御、OCX不要</td><td>依存関係と更新を手動で管理する必要あり</td></tr></tbody></table><p><strong>推奨</strong>：OCXでのインストールを優先してください。より手軽です。</p><h3 id="ステップ2-ocxでインストール-推奨" tabindex="-1">ステップ2：OCXでインストール（推奨） <a class="header-anchor" href="#ステップ2-ocxでインストール-推奨" aria-label="Permalink to &quot;ステップ2：OCXでインストール（推奨）&quot;">​</a></h3><h4 id="_2-1-ocxパッケージマネージャーをインストール" tabindex="-1">2.1 OCXパッケージマネージャーをインストール <a class="header-anchor" href="#_2-1-ocxパッケージマネージャーをインストール" aria-label="Permalink to &quot;2.1 OCXパッケージマネージャーをインストール&quot;">​</a></h4><p>OCXはOpenCodeの公式プラグインパッケージマネージャーで、プラグインのインストール、更新、管理を簡単に行えます。</p><p><strong>OCXをインストール</strong>：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -fsSL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://ocx.kdco.dev/install.sh</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> sh</span></span></code></pre></div><p><strong>期待される出力</strong>：インストールスクリプトが進捗を表示し、最後にインストール成功のメッセージが表示されます。</p><h4 id="_2-2-kdco-registryを追加" tabindex="-1">2.2 KDCO Registryを追加 <a class="header-anchor" href="#_2-2-kdco-registryを追加" aria-label="Permalink to &quot;2.2 KDCO Registryを追加&quot;">​</a></h4><p>KDCO Registryは、opencode-notifyなど複数の実用的なプラグインを含むプラグインリポジトリです。</p><p><strong>registryを追加</strong>：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ocx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> registry</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://registry.kdco.dev</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --name</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> kdco</span></span></code></pre></div><p><strong>期待される出力</strong>：「Registry added successfully」または同様のメッセージが表示されます。</p><div class="tip custom-block"><p class="custom-block-title">オプション：グローバル設定</p><p>すべてのプロジェクトで同じregistryを使用したい場合は、<code>--global</code>パラメータを追加してください：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ocx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> registry</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://registry.kdco.dev</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --name</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> kdco</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --global</span></span></code></pre></div></div><h4 id="_2-3-opencode-notifyをインストール" tabindex="-1">2.3 opencode-notifyをインストール <a class="header-anchor" href="#_2-3-opencode-notifyをインストール" aria-label="Permalink to &quot;2.3 opencode-notifyをインストール&quot;">​</a></h4><p><strong>プラグインをインストール</strong>：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ocx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> kdco/notify</span></span></code></pre></div><p><strong>期待される出力</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>✓ Added kdco/notify to your OpenCode workspace</span></span></code></pre></div><h3 id="ステップ3-ワークスペース全体を一括インストール-オプション" tabindex="-1">ステップ3：ワークスペース全体を一括インストール（オプション） <a class="header-anchor" href="#ステップ3-ワークスペース全体を一括インストール-オプション" aria-label="Permalink to &quot;ステップ3：ワークスペース全体を一括インストール（オプション）&quot;">​</a></h3><p>完全な体験を得たい場合は、KDCOワークスペースをインストールできます。以下が含まれます：</p><ul><li>opencode-notify（デスクトップ通知）</li><li>バックグラウンドエージェント（Background Agents）</li><li>専門エージェント（Specialist Agents）</li><li>プランニングツール（Planning Tools）</li></ul><p><strong>ワークスペースをインストール</strong>：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ocx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> kdco/workspace</span></span></code></pre></div><p><strong>期待される出力</strong>：複数のコンポーネントが正常に追加されたことを示すメッセージが表示されます。</p><h3 id="ステップ4-インストールを確認" tabindex="-1">ステップ4：インストールを確認 <a class="header-anchor" href="#ステップ4-インストールを確認" aria-label="Permalink to &quot;ステップ4：インストールを確認&quot;">​</a></h3><p>インストール完了後、通知をトリガーして設定が正しいか確認しましょう。</p><p><strong>確認方法1：AIにタスクを完了させる</strong></p><p>OpenCodeで以下を入力：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1から10までの合計を計算し、5秒待ってから結果を教えてください。</span></span></code></pre></div><p>別のウィンドウに切り替えて数秒作業すると、デスクトップ通知がポップアップするはずです。</p><p><strong>確認方法2：設定ファイルを確認</strong></p><p>設定ファイルが存在するか確認：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># macOS/Linux</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cat</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.config/opencode/kdco-notify.json</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Windows PowerShell</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">type</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> $env</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">:USERPROFILE</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\.</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">config</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\o</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">pencode</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\k</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">dco-notify.json</span></span></code></pre></div><p><strong>期待される出力</strong>：</p><ul><li>ファイルが存在しない場合 → デフォルト設定を使用中（正常）</li><li>ファイルが存在する場合 → カスタム設定が表示される</li></ul><h3 id="ステップ5-手動インストール-代替方法" tabindex="-1">ステップ5：手動インストール（代替方法） <a class="header-anchor" href="#ステップ5-手動インストール-代替方法" aria-label="Permalink to &quot;ステップ5：手動インストール（代替方法）&quot;">​</a></h3><p>OCXを使用したくない場合は、手動でインストールできます。</p><h4 id="_5-1-ソースコードをコピー" tabindex="-1">5.1 ソースコードをコピー <a class="header-anchor" href="#_5-1-ソースコードをコピー" aria-label="Permalink to &quot;5.1 ソースコードをコピー&quot;">​</a></h4><p>opencode-notifyのソースコードをOpenCodeプラグインディレクトリにコピー：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># ソースコードを専用ディレクトリにコピー</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mkdir</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.opencode/plugin/kdco-notify</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> src/notify.ts</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.opencode/plugin/kdco-notify/</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cp</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -r</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> src/plugin/kdco-primitives</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.opencode/plugin/kdco-notify/</span></span></code></pre></div><h4 id="_5-2-依存関係をインストール" tabindex="-1">5.2 依存関係をインストール <a class="header-anchor" href="#_5-2-依存関係をインストール" aria-label="Permalink to &quot;5.2 依存関係をインストール&quot;">​</a></h4><p>必要な依存関係を手動でインストール：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.opencode/plugin/</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> node-notifier</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> detect-terminal</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @opencode-ai/plugin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @opencode-ai/sdk</span></span></code></pre></div><div class="warning custom-block"><p class="custom-block-title">注意事項</p><ul><li><strong>依存関係の管理</strong>：<code>node-notifier</code>と<code>detect-terminal</code>を手動でインストール・更新する必要があります</li><li><strong>更新が困難</strong>：更新のたびにソースコードを手動で再コピーする必要があります</li><li><strong>非推奨</strong>：特別な要件がない限り、OCXでのインストールを推奨します</li></ul></div><h3 id="チェックポイント-✅" tabindex="-1">チェックポイント ✅ <a class="header-anchor" href="#チェックポイント-✅" aria-label="Permalink to &quot;チェックポイント ✅&quot;">​</a></h3><p>上記の手順を完了したら、以下を確認してください：</p><ul><li>[ ] OCXのインストール成功（<code>ocx --version</code>でバージョン番号が出力される）</li><li>[ ] KDCO Registryが追加済み（<code>ocx registry list</code>でkdcoが表示される）</li><li>[ ] opencode-notifyがインストール済み（<code>ocx list</code>でkdco/notifyが表示される）</li><li>[ ] 最初のデスクトップ通知を受信</li><li>[ ] 通知に正しいタスクタイトルが表示される</li></ul><p><strong>いずれかのステップで失敗した場合</strong>：</p><ul><li><a href="./../../faq/troubleshooting/">トラブルシューティング</a>を参照</li><li>OpenCodeが正常に動作しているか確認</li><li>システムがデスクトップ通知をサポートしているか確認</li></ul><h2 id="よくある問題と解決策" tabindex="-1">よくある問題と解決策 <a class="header-anchor" href="#よくある問題と解決策" aria-label="Permalink to &quot;よくある問題と解決策&quot;">​</a></h2><h3 id="よくある問題1-通知が表示されない" tabindex="-1">よくある問題1：通知が表示されない <a class="header-anchor" href="#よくある問題1-通知が表示されない" aria-label="Permalink to &quot;よくある問題1：通知が表示されない&quot;">​</a></h3><p><strong>原因</strong>：</p><ul><li>macOS：システム通知がオフになっている</li><li>Windows：通知権限が付与されていない</li><li>Linux：notify-sendがインストールされていない</li></ul><p><strong>解決方法</strong>：</p><table tabindex="0"><thead><tr><th>プラットフォーム</th><th>解決方法</th></tr></thead><tbody><tr><td>macOS</td><td>システム設定 → 通知 → OpenCode → 通知を許可</td></tr><tr><td>Windows</td><td>設定 → システム → 通知 → 通知をオン</td></tr><tr><td>Linux</td><td>libnotify-binをインストール：<code>sudo apt install libnotify-bin</code></td></tr></tbody></table><h3 id="よくある問題2-ocxのインストールに失敗" tabindex="-1">よくある問題2：OCXのインストールに失敗 <a class="header-anchor" href="#よくある問題2-ocxのインストールに失敗" aria-label="Permalink to &quot;よくある問題2：OCXのインストールに失敗&quot;">​</a></h3><p><strong>原因</strong>：ネットワークの問題または権限不足</p><p><strong>解決方法</strong>：</p><ol><li>ネットワーク接続を確認</li><li>sudoでインストール（管理者権限が必要）</li><li>インストールスクリプトを手動でダウンロードして実行</li></ol><h3 id="よくある問題3-依存関係のインストールに失敗" tabindex="-1">よくある問題3：依存関係のインストールに失敗 <a class="header-anchor" href="#よくある問題3-依存関係のインストールに失敗" aria-label="Permalink to &quot;よくある問題3：依存関係のインストールに失敗&quot;">​</a></h3><p><strong>原因</strong>：Node.jsのバージョンが非互換</p><p><strong>解決方法</strong>：</p><ul><li>Node.js 18以上を使用</li><li>npmキャッシュをクリア：<code>npm cache clean --force</code></li></ul><h2 id="このレッスンのまとめ" tabindex="-1">このレッスンのまとめ <a class="header-anchor" href="#このレッスンのまとめ" aria-label="Permalink to &quot;このレッスンのまとめ&quot;">​</a></h2><p>このレッスンで完了したこと：</p><ul><li>✅ OCXパッケージマネージャーのインストール</li><li>✅ KDCO Registryの追加</li><li>✅ opencode-notifyプラグインのインストール</li><li>✅ 最初のデスクトップ通知のトリガー</li><li>✅ 手動インストール方法の理解</li></ul><p><strong>重要なポイント</strong>：</p><ol><li>opencode-notifyはネイティブデスクトップ通知を使用し、頻繁なウィンドウ切り替えが不要</li><li>OCXは推奨されるインストール方法で、依存関係と更新を自動管理</li><li>デフォルトでは親セッションのみ通知し、サブタスクのノイズを回避</li><li>ターミナルがフォーカスされている時は自動的に通知を抑制</li></ol><h2 id="次のレッスン予告" tabindex="-1">次のレッスン予告 <a class="header-anchor" href="#次のレッスン予告" aria-label="Permalink to &quot;次のレッスン予告&quot;">​</a></h2><blockquote><p>次のレッスンでは**<a href="./../how-it-works/">動作原理</a>**を学びます。</p><p>学べること：</p><ul><li>プラグインがOpenCodeイベントを監視する仕組み</li><li>スマートフィルタリング機構のワークフロー</li><li>ターミナル検出とフォーカス検知の原理</li><li>プラットフォームごとの機能差異</li></ul></blockquote><hr><h2 id="付録-ソースコード参照" tabindex="-1">付録：ソースコード参照 <a class="header-anchor" href="#付録-ソースコード参照" aria-label="Permalink to &quot;付録：ソースコード参照&quot;">​</a></h2><details><summary><strong>クリックしてソースコードの場所を表示</strong></summary><blockquote><p>更新日：2026-01-27</p></blockquote><table tabindex="0"><thead><tr><th>機能</th><th>ファイルパス</th><th>行番号</th></tr></thead><tbody><tr><td>プラグインメインエントリ</td><td><a href="https://github.com/kdcokenny/opencode-notify/blob/main/src/notify.ts#L1-L407" target="_blank" rel="noreferrer"><code>src/notify.ts</code></a></td><td>1-407</td></tr><tr><td>設定読み込み</td><td><a href="https://github.com/kdcokenny/opencode-notify/blob/main/src/notify.ts#L90-L114" target="_blank" rel="noreferrer"><code>src/notify.ts</code></a></td><td>90-114</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>通知送信</td><td><a href="https://github.com/kdcokenny/opencode-notify/blob/main/src/notify.ts#L280-L308" target="_blank" rel="noreferrer"><code>src/notify.ts</code></a></td><td>280-308</td></tr><tr><td>ターミナル検出</td><td><a href="https://github.com/kdcokenny/opencode-notify/blob/main/src/notify.ts#L145-L176" target="_blank" rel="noreferrer"><code>src/notify.ts</code></a></td><td>145-176</td></tr><tr><td>サイレント時間帯チェック</td><td><a href="https://github.com/kdcokenny/opencode-notify/blob/main/src/notify.ts#L181-L199" target="_blank" rel="noreferrer"><code>src/notify.ts</code></a></td><td>181-199</td></tr><tr><td>デフォルト設定</td><td><a href="https://github.com/kdcokenny/opencode-notify/blob/main/src/notify.ts#L30-L48" target="_blank" rel="noreferrer"><code>src/notify.ts</code></a></td><td>30-48</td></tr></tbody></table><p><strong>主要な定数</strong>：</p><ul><li><code>DEFAULT_CONFIG.sounds.idle = &quot;Glass&quot;</code>：タスク完了時のデフォルトサウンド</li><li><code>DEFAULT_CONFIG.sounds.error = &quot;Basso&quot;</code>：エラー時のデフォルトサウンド</li><li><code>DEFAULT_CONFIG.sounds.permission = &quot;Submarine&quot;</code>：権限リクエスト時のデフォルトサウンド</li><li><code>DEFAULT_CONFIG.notifyChildSessions = false</code>：デフォルトで親セッションのみ通知</li></ul><p><strong>主要な関数</strong>：</p><ul><li><code>NotifyPlugin()</code>：プラグインエントリ関数、イベントハンドラを返す</li><li><code>loadConfig()</code>：設定ファイルを読み込み、デフォルト値とマージ</li><li><code>sendNotification()</code>：ネイティブデスクトップ通知を送信</li><li><code>detectTerminalInfo()</code>：ターミナルタイプとBundle IDを検出</li><li><code>isQuietHours()</code>：現在時刻がサイレント時間帯かどうかをチェック</li><li><code>isParentSession()</code>：親セッションかどうかを判定</li><li><code>isTerminalFocused()</code>：ターミナルがフォアグラウンドウィンドウかどうかを検出</li></ul></details>`,94)])])}const g=t(n,[["render",o]]);export{k as __pageData,g as default};
